INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1981, 205759, 10, 690, '[转贴]梦里花落知多少⑦', '我也是一上班族了，还是一小白领。想想就兴奋。这一兴奋的状态持续了好几个星期，陆叙表扬我说我工作特别卖力，而且创意层出不穷跟黄河泛滥似的。我踢他一脚说你真不会用词。他跟贼似的嘿嘿笑两声，然后又站直了身子摇头晃脑地特严肃地拿上司的身份压我，整个一大尾巴狼。 
<br>������每天早上我就乘车去上班，朝九晚五的，隔三差五的还要陪陆叙这个自虐狂熬夜加班。陆叙想不出点子来的时候就特烦躁，跟一狮子似的，用手猛抓头发，一个头乱得跟木村拓栽似的。他不但自虐还要虐我，不准我回家，不过加班费付地特别爽快，我也没说什么。就陪着他在那浪费光阴。 
<br>������我发现自己进入了一种前所未有的工作状态，那叫一投入，这事发生在我身上真叫一稀罕。我连回家之后都拿着广告计划案在那想创意，一边想还一边自个儿在空中挥舞着我的鸡爪子，摇头晃脑跟一说书先生似的指点江山激扬文字。开始的时候我妈特高兴，这小老太太说，林岚你这样还像个人。您说这话多新鲜啊，那前面二十年我是一木鸡还是一石猴啊。可是后来我妈就经不住陆叙的电话轰炸了。陆叙这人真变态，每天晚上深夜准时有电话，而且都是挑那种凌晨两三点，也就是骚扰电话频繁出现的时段打给我。我妈开始以为我惹着什么道儿上的人了，老被电话骚扰，准备叫我爸找人去把这事儿给撩平了。我告儿我妈这是公事电话，我妈眼睛瞪出来跟见鬼似的。不过我妈特喜欢陆叙那人，因为上次陆叙来我家拿一文件，我妈听说是我的顶头上司，立马端茶倒水跟伺候一土地公公似的，陆叙这人又特会装孙子，长得好看秀气，又温文尔雅，在我妈心里的印象分蹭立马就上去了。我在旁边直嘀咕，小样儿，有种你把在办公室扯着脖子跟我叫板儿那操行给弄出来啊。陆叙趁我妈倒茶的时候冲我特阴险地笑，整个儿一大尾巴狼。 
<br>������以后陆叙打电话来凡是我妈接的话，那就没我什么事了，我妈在电话里嘘寒问暖的跟问候一留学出国的儿子似的。我就在心里呐喊啊：二十年前从你肚子里横空出世的那可是我啊，怎么没见着你对我这么上心啊。我在旁边咕咚咕咚地喝水，弄出特大的声响以表示我的不满。可我妈就当我一空气。 
<br>������在陆叙的无数个深夜电话的袭击下，我妈终于崩溃了。是她最心爱的留学儿子打的她能说什么啊，只是用一种特哀怨的眼神望着我望得我心里直发毛。我妈说她得了神经衰弱了。其实别说我妈，就连我都有点撑不住了，这一什么上司啊，跟一吸血鬼似的，比周扒皮还扒皮。于是我就立马给我妈还顺带给我买了十多盒某某安神补脑液，可这年头虚假广告太多了，这些人真他妈黑心。说完之后立马醒悟我也是一做广告的，前阵子不也还替一灭蚊器材厂天上地下地猛吹了一翻吗，就我弄出来那阵仗别说一蚊子，就一飞机都得给我熏下来。 
<br>������看着我妈那样我也心疼啊。整天一脸苍白跟鬼似的在客厅里飘来飘去，叫她一声妈隔五秒钟转过头来缓慢地问你“啥事儿”，整个一恐怖片里的贞子。我想这样也不是办法啊，于是跑去跟陆叙反映了这情况，希望申请一职工宿舍望批准。当时我问得特礼貌其实心里在摩拳擦掌你要敢不答应我当场把你挂了。没想到陆叙想也没想就答应了，真爽快，如果他真是一嫖客估计也特爽快。 
<br>������我回家告诉我妈我要搬出去了，我妈一听蹭的从沙发上蹦起来上窜下跳，撒丫子满屋飞奔给我收拾东西，动作矫健迅如惊雷，整个儿一女蜘蛛侠，看她那样儿就差没说“快点走走了就别回来”了。这哪像一神经衰弱患者啊，整个一神经亢奋。还没嫁人呢就把我往外赶，这一什么老太太啊！我突然想起我妈也经常一脸仇深似海地对我说“这一什么小孩儿啊”。我想这多新鲜啊，孩子又不是我生的您来问我。 
<br>
<br>������那天和陆叙去申请宿舍，那个女部门经理特有派头，比微微都老佛爷。不过还是蛮顺利的，那女的从我进去到出来正眼都没看我一眼，只告诉陆叙还有一间，六幢302。当时陆叙表情特诡异。出来的时候他说，你住我旁边。我说哦。他说真倒霉。我就不明白了，他说怕我哪天喝高了侵犯他。我当时被那句话弄蒙了，半天才回过劲儿来，这好像是我的台词吧，咱俩谁是大老爷们儿啊。等我要龇牙咧嘴地扑过去的时候陆叙早就走了。我心里堵了一上午，真他妈憋死我了。 
<br>
<br>我就这么轰轰烈烈地搬家了，我搬家那天弄得整个小区都在地震，主要是我死活让搬家队把我那一张惊世骇俗的床也给搬了去。我站在卡车旁边指手画脚地叫那些人当心我的一切东西，跟一站在前线运筹帷幄的女将军似的。社区的大妈拉着我妈的手特激动地说：终于嫁出去了，终于嫁出去了啊！看她那像要热泪盈眶的样子就跟她自己终于嫁出去了似的那么激动。我妈在旁边脸绷得跟牛皮鼓似的，半天咬牙切齿地说，她没嫁人，就搬出去住会儿。 
<br>等我弄完我搬家那事儿已经晚上八点多了，我累得倒在床上，跟一脱了线的木偶似的一动也动不了。我脖子疼手疼脚疼，就跟被人拖进黑巷子给揍了一顿似的。我躺在床上心里琢磨着怎么一时冲动就从家里那两百多平米的地儿搬到这几十平米的破小屋来了呢。 
<br>正琢磨着，电话来了，我他妈真是不想接啊，躺在床上装尸体，可那打电话的人特执着，整死不挂。最后我还是伸出手去接了，动作比电视剧里垂死的人都慢，还抖啊抖的。电话一接起来听到闻婧在那边一声“嗷――”我立马眼前一黑，心里叫得比她都惨烈。 
<br>我又跟女特务似的雷厉风行地出了门，打了辆车就往钱柜冲。闻婧打电话给我妈，然后我妈就把我搬家这事儿给告儿她了。一说倒好，闻婧立马来了一票人去钱柜开歌，几个人一边唱着马都能吓死的歌一边等着我去那儿买单，美其名曰“庆祝我乔迁之喜”，真他妈名副其实的“说”的比“唱”得还好听。 
<br>我对司机说叫他怎么慢怎么开，耽误了他生意我多付他个起步费，因为我想在车上继续眯会儿。那师傅把头转过来特迷茫地看着我，估计没整明白，我从倒后镜里看到自己一脸菜色就对他说，师傅，我病了。他还是很疑惑，他说病了往医院开啊，怎么还慢悠悠地朝钱柜开呢，小姑娘不要命拉。我连解释都懒得跟他解释了，就说，得师傅，您爱怎么开怎么开。 
<br>估计那男的被我吓着了，怕我真病严重了还没到钱柜就死在他车上，所以把车开得飞快，我才一眯眼一睁眼立马车窗外就霓虹闪烁妖孽横行了。北京的交通什么时候变得这么通畅的，以前不是老便秘吗？ 
<br>我冲进包间，看见闻婧正在那啃西瓜，周围的人有某某某，某某某，反正就是我闭着眼睛也能猜到的那些人。白松和他的小茉莉坐在房间的角落里缠绵悱恻的，顾小北坐在姚姗姗的旁边没说话，一直盯着手机屏幕，我进来的时候他抬起头看了我三秒钟，似乎想要说什么话但最终又没说，低下头继续看手机。我用脚踹翻几个人然后挤到闻婧身边坐下来，恶狠狠地对她说，你真他妈一妖孽。 
<br>说完之后我就躺在沙发上睡觉，真没劲。睡到一半有人拍我的肩膀，我睁开眼睛就看到顾小北已经坐到我旁边了。他看着我的脸，很严肃地对我说，林岚，帮我个忙吧。我知道顾小北是不轻易求人的，所以我坐直了身子，想也没想就说，只要我做的到的我一定帮你，什么事说吧。 
<br>其实是一直因为我觉得自己欠了顾小北太多东西，能还点我就要还。从高一和他谈恋爱一直到大三，六年了，六年里面顾小北什么都听我的，宠着我，惯着我，惯得我毛病。他总是笑眯眯地望着我，一脸的温柔，眼睛亮晶晶的跟北极星似的。连最后一次我说要分手他都二话没说地听我的。分手那天是在我家里面，他重感冒，戴着我送他的很厚很厚的帽子手套围巾，全身裹得严严实实跟一东北大兴安岭的老大爷似的。我说我们分手吧，他点头，然后他上洗手间，**在洗手间的门外面听到里面大声的连续不断的咳嗽声，水龙头的声音，抽水马桶哗哗的水声。在那些声音里面，我隐约地听到顾小北低沉的哭泣的声音，很轻很模糊，跟他讲话的声音一样温柔。**在门上身子一点一点滑下去，眼泪跟长江决口似的往外冲。 
<br>那天我把顾小北送到门口，他笑着摸我的头发，他说以后你肯定和你的新男朋友吵架跟吃饭似的一天三顿，除了我谁受得了你的狗脾气啊。我当时望着顾小北的样子心里跟刀割似的，如果他当时说不分手，或者只是说一下“你要不要再考虑看看”，我绝对扑在他怀里说不要分开。可顾小北太听我的话了，电脑删除文件都还让你确定一下YES or No呢，他直接就把我的话给执行了。', '我也是一上班族了，还是一小白领。想想就兴奋。这一兴奋的状态持续了好几个星期，陆叙表扬我说我工作特别卖力，而且创意层出不穷跟黄河泛滥似的。我踢他一脚说你真不会用词。他跟贼似的嘿嘿笑两声，然后又站直了身子摇头晃脑地特严肃地拿上司的身份压我，整个一大尾巴狼。

